#!/usr/bin/env node
const { spawn, execSync } = require('child_process')
const path = require('path')

module.exports = {
  start () {
    console.log('🚀 Starting backend websocket daemon...')
    const serverPath = path.join(__dirname, '../../../lib/server.js')
    const child = spawn('node', [serverPath], { detached: true, stdio: 'ignore' })
    child.unref()
    console.log('✅ WebSocket daemon started.')
  },

  stop () {
    console.log('🛑 Stopping backend websocket daemon...')
    try {
      execSync('pkill -f lib/server.js', { stdio: 'ignore' })
      console.log('✅ WebSocket daemon stopped.')
    } catch {
      console.log('No websocket daemon found.')
    }
  }
}
